```python
import os
import pickle

class IndexCache:
    def __init__(self, index_file_path):
        self.index_file_path = index_file_path
        self.cache_file_path = os.path.join(os.path.dirname(index_file_path), f'{os.path.basename(index_file_path)}.cache')

    def load(self):
        if os.path.exists(self.cache_file_path):
            with open(self.cache_file_path, 'rb') as f:
                return pickle.load(f)
        return {}

    def save(self, cache):
        with open(self.cache_file_path, 'wb') as f:
            pickle.dump(cache, f)

    def clear(self):
        if os.path.exists(self.cache_file_path):
            os.remove(self.cache_file_path)

# Example usage
